import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Wallet, ArrowRight, ShoppingBag, CreditCard, LayoutDashboard } from 'lucide-react';
import { Link } from 'react-router-dom';

const Menu = () => {
  const [resumo, setResumo] = useState({ total: 0, quantidade: 0, totalCartoes: 0 });

  useEffect(() => {
    async function buscarDados() {
      // Busca resumo de compras
      const { data: compras } = await supabase.from('compras').select('valor_total');
      // Busca quantidade de cartões
      const { data: cartoes } = await supabase.from('cartoes').select('id');

      if (compras) {
        const soma = compras.reduce((acc, item) => acc + parseFloat(item.valor_total), 0);
        setResumo(prev => ({ 
          ...prev, 
          total: soma, 
          quantidade: compras.length,
          totalCartoes: cartoes ? cartoes.length : 0
        }));
      }
    }
    buscarDados();
  }, []);

  const colors = {
    primary: '#4361ee',
    secondary: '#7209b7',
    success: '#4caf50',
    card: 'linear-gradient(135deg, #4361ee, #4cc9f0)',
    credit: 'linear-gradient(135deg, #7209b7, #f72585)'
  };

  return (
    <div className="fade-in" style={{ padding: '20px' }}>
      <header style={{ marginBottom: '40px' }}>
        <h1 style={{ fontSize: '2.2rem', margin: 0, fontWeight: 800 }}>Olá! 👋</h1>
        <p style={{ color: '#636e72', fontSize: '1.1rem' }}>Aqui está o que está acontecendo nas suas finanças.</p>
      </header>

      {/* INDICADORES PRINCIPAIS */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '20px', marginBottom: '40px' }}>
        
        <div className="card" style={{ borderLeft: `6px solid ${colors.primary}`, padding: '25px', boxShadow: '0 10px 20px rgba(0,0,0,0.05)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ color: '#636e72', fontWeight: '700', fontSize: '0.8rem', textTransform: 'uppercase' }}>Gasto Acumulado</span>
            <Wallet size={24} color={colors.primary} />
          </div>
          <h2 style={{ fontSize: '2rem', margin: '15px 0 5px 0', fontWeight: 800 }}>
            R$ {resumo.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </h2>
          <small style={{ color: '#b2bec3' }}>Total histórico de compras</small>
        </div>

        <div className="card" style={{ borderLeft: `6px solid ${colors.success}`, padding: '25px', boxShadow: '0 10px 20px rgba(0,0,0,0.05)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ color: '#636e72', fontWeight: '700', fontSize: '0.8rem', textTransform: 'uppercase' }}>Lançamentos</span>
            <ShoppingBag size={24} color={colors.success} />
          </div>
          <h2 style={{ fontSize: '2rem', margin: '15px 0 5px 0', fontWeight: 800 }}>{resumo.quantidade}</h2>
          <small style={{ color: '#b2bec3' }}>Itens registrados no sistema</small>
        </div>

      </div>

      {/* ACESSOS RÁPIDOS (CARDS COLORIDOS) */}
      <h3 style={{ marginBottom: '20px', color: '#2d3436' }}>Ações Rápidas</h3>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px' }}>
        
        {/* LINK DASHBOARD */}
        <Link to="/dashboard" style={{ textDecoration: 'none' }}>
          <div className="card" style={{ background: colors.card, color: 'white', padding: '25px', borderRadius: '20px', height: '100%' }}>
            <LayoutDashboard size={32} style={{ marginBottom: '15px', opacity: 0.9 }} />
            <h3 style={{ margin: '0 0 10px 0', fontSize: '1.2rem' }}>Painel Geral</h3>
            <p style={{ fontSize: '0.85rem', opacity: 0.9, margin: 0 }}>Análise detalhada de gastos por pessoa.</p>
          </div>
        </Link>

        {/* LINK CARTÕES */}
        <Link to="/cartoes" style={{ textDecoration: 'none' }}>
          <div className="card" style={{ background: colors.credit, color: 'white', padding: '25px', borderRadius: '20px', height: '100%' }}>
            <CreditCard size={32} style={{ marginBottom: '15px', opacity: 0.9 }} />
            <h3 style={{ margin: '0 0 10px 0', fontSize: '1.2rem' }}>Meus Cartões</h3>
            <p style={{ fontSize: '0.85rem', opacity: 0.9, margin: 0 }}>{resumo.totalCartoes} cartões cadastrados.</p>
          </div>
        </Link>

        {/* LINK NOVO GASTO */}
        <Link to="/lancamento" style={{ textDecoration: 'none' }}>
          <div className="card" style={{ background: '#2d3436', color: 'white', padding: '25px', borderRadius: '20px', height: '100%', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', textAlign: 'center' }}>
            <div style={{ background: 'rgba(255,255,255,0.1)', padding: '15px', borderRadius: '50%', marginBottom: '10px' }}>
              <ArrowRight size={24} />
            </div>
            <span style={{ fontWeight: 700 }}>Novo Lançamento</span>
          </div>
        </Link>

      </div>
    </div>
  );
};

export default Menu;
